tools = [
    {
        "name": "get_weather",
        "description": (
            "Возвращает текущую погоду в городе. "
            "Вызывай, когда пользователь спрашивает о погоде, температуре или осадках."
        ),
        "input_schema": {
            "type": "object",
            "properties": {
                "city": {"type": "string", "description": "Название города, например: Казань"},
                "unit": {"type": "string", "enum": ["celsius", "fahrenheit"]},
            },
            "required": ["city"],
        },
    }
]

let messages: Anthropic.MessageParam[] = [
  { role: "user", content: "Какая погода в Казани?" },
];

while (true) {
  const response = await client.messages.create({
    model: "claude-opus-4-8",
    max_tokens: 1024,
    tools,
    messages,
  });

  if (response.stop_reason !== "tool_use") break; // готов финальный ответ

  messages.push({ role: "assistant", content: response.content });

  const results = [];
  for (const block of response.content) {
    if (block.type === "tool_use") {
      const result = await runTool(block.name, block.input); // твоя функция
      results.push({ type: "tool_result", tool_use_id: block.id, content: result });
    }
  }
  messages.push({ role: "user", content: results });
}
